const clients = [
  {
    id: 'alfa',
    name: 'Alfa Construction Inc.',
    ghlKey: 'YOUR_GHL_KEY',
    email: 'info@alfapaintingcarpentry.com',
    phone: '+15085963750',
    site: 'https://www.alfapaintingcarpentry.com/',
    language: 'en'
  },
  // ADD MORE CLIENTS:
  // { id: 'client2', name: '...', ghlKey: '...', email: '...', phone: '+1...', site: 'https://...', language: 'en' },
];

return clients.map(c => ({ json: c }));

const client = $('Client List (EDIT THIS)').item.json;
const contactsData = $('GHL — Get Contacts').item.json;
const pipelinesData = $('GHL — Get Pipelines').item.json;

const contacts = contactsData.contacts || [];
const sources = {};
contacts.forEach(c => {
  const s = c.source || c.tags?.[0] || 'Direct';
  sources[s] = (sources[s] || 0) + 1;
});

const pipelines = pipelinesData.pipelines || [];
const pipeInfo = pipelines.map(p => p.name + ' (' + p.stages.length + ' stages)').join(', ');

const now = new Date();
return [{ json: {
  ...client,
  totalContacts: contacts.length,
  leadSources: JSON.stringify(sources),
  pipelines: pipeInfo,
  monthName: now.toLocaleString('en-US', { month: 'long', year: 'numeric' }),
  period: new Date(now.getTime()-30*24*60*60*1000).toISOString().split('T')[0] + ' to ' + now.toISOString().split('T')[0]
}}];

